import java.util.*;class P5{static char[] uniq(String s){char[] r=new char[s.length()];int k=0;for(int i=0;i<s.length();i++){char c=s.charAt(i);boolean f=true;for(int j=0;j<i;j++)if(s.charAt(j)==c)f=false;if(f)r[k++]=c;}char[] u=new char[k];for(int i=0;i<k;i++)u[i]=r[i];return u;}public static void main(String[] a){Scanner s=new Scanner(System.in);String t=s.next();int[] f=new int[256];for(int i=0;i<t.length();i++)f[t.charAt(i)]++;char[] u=uniq(t);for(char c:u)System.out.println(c+" "+f[c]);}}